        return [];
    }

    // Map to store sum -> count of representations
    const sumCounts = new Map();

    // Determine max_b such that 1^3 + max_b^3 <= n
    // Since a >= 1, b^3 <= n - 1.
    let max_b = 0;
    for (let b = 1; ; b++) {
        const bCubed = b * b * b;
        if (bCubed >= n) {
            // If b^3 >= n, then for a=1, 1^3 + b^3 >= n+1 (unless b^3=n and a=0, but a>=1)
            // Since a >= 1, we need 1 + b^3 <= n, so b^3 <= n - 1.
            max_b = b - 1;
            break;
        }
        max_b = b;
    }

    for (let b_val = 1; b_val <= max_b; b_val++) {
        const bCubed = b_val * b_val * b_val;

